            if (!isInitialized.current) {
              if (view === 'auth') setView('dashboard');
              setShowGuide(true);
              isInitialized.current = true;
            }

            // Referral Listener
            // Check if user has a referral code, then query the 'referrals' collection
            if (userData.referralCode && userData.referralCode !== currentReferralCodeListener) {
                if (unsubRefs) unsubRefs(); // Clean up old listener
                currentReferralCodeListener = userData.referralCode;

                const q = query(
                    collection(db, 'referrals'), 
                    where('referredBy', '==', userData.referralCode)
                );

                unsubRefs = onSnapshot(q, 
                  (snap) => { 
                      const refs = snap.docs.map(d => sanitizeDoc(d) as ReferralRecord);
                      // Sort by join date descending (newest first)
                      refs.sort((a, b) => (b.joinedAt || 0) - (a.joinedAt || 0));
                      setMyReferrals(refs); 
                  },
                  (err) => console.warn("Referral listener restricted:", err.message)
                );
            }

          } else {
            setIsProvisioning(true);
            setIsLoading(false);
          }
        }, (err) => {
          console.error("Profile listen error:", err.message);
          setAuthError("Session synchronization error: " + err.message);
          setIsLoading(false);
        });

        unsubTx = onSnapshot(
          query(collection(db, 'transactions'), where('userId', '==', firebaseUser.uid)), 
          (snap) => {
            const txs = snap.docs.map(d => sanitizeDoc(d) as Transaction);
            setTransactions(txs.sort((a, b) => b.timestamp - a.timestamp));
          },
          (err) => console.warn("Tx listener restricted")
        );

        unsubPk = onSnapshot(
          query(collection(db, 'activePackages'), where('userId', '==', firebaseUser.uid)), 
          (snap) => {
            const pkgs = snap.docs.map(d => sanitizeDoc(d) as UserPackage);
            setActivePackages(pkgs);
          },
          (err) => console.warn("Active Pkg listener restricted")
        );

      } else {
        setCurrentUser(null);
        setTransactions([]);
        setActivePackages([]);
        setMyReferrals([]);
        setView('auth');
        setIsLoading(false);
        setIsProvisioning(false);
        setShowLanding(true);
        isInitialized.current = false;
        setShowGuide(false);
      }
    });

    return () => {
      unsubscribeAuth();
      if (unsubUser) unsubUser();
      if (unsubTx) unsubTx();
      if (unsubPk) unsubPk();
      if (unsubRefs) unsubRefs();
    };
  }, []);

  const handleLogin = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setAuthError(null);
    try {
      await signInWithEmailAndPassword(auth, email, password);
    } catch (error: any) {
      setAuthError(error?.message || "Login failed");
      setIsLoading(false);
    }
  };

  const handleRegister = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setIsProvisioning(true);
    setAuthError(null);
    try {
      const cred = await createUserWithEmailAndPassword(auth, email, password);
      await createFirestoreUser(cred.user.uid, email, refCode);
    } catch (error: any) {
      setAuthError(error?.message || 'Registration failed');
      setIsLoading(false);
      setIsProvisioning(false);
      if (auth.currentUser) await signOut(auth);
    }
  };

  const handlePasswordReset = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!email) {
      setAuthError("Please enter your email.");
      return;
    }
    setIsLoading(true);
    try {
      await sendPasswordResetEmail(auth, email);
      alert("Password reset link sent!");
      setAuthMode('login');
    } catch (error: any) {
      setAuthError(error?.message || "Reset failed");
    } finally {
      setIsLoading(false);
    }
  };

  const handleLogout = async () => {
    try {
      setIsLoading(true);
      await signOut(auth);
      setShowLanding(true);
    } catch (err: any) {
      setIsLoading(false);
    }
  };

  const handleWithdrawal = async (amount: number, address: string) => {
    if (!currentUser) return;
    if (amount < platformSettings.minWithdrawal) {
      alert(`Min withdrawal is $${platformSettings.minWithdrawal}`);
      return;
    }
    try {
      await requestWithdrawalFirestore(currentUser.id, amount, address);
      alert('Withdrawal requested.');
    } catch (err: any) {
      alert(err?.message || 'Withdrawal failed');
    }
  };

  const handleDepositSync = async () => {
    if (!currentUser) return;
    try {
      await syncUserDepositsFirestore(currentUser.id);
      alert('Sync complete.');
    } catch (err: any) {
      alert('Sync Failed: ' + (err?.message || 'Error'));
    }
  };

  const handleBonusClaim = async (e: React.FormEvent) => {
    e.preventDefault();
    if (!currentUser || !bonusCode.trim()) return;
    setIsClaimingBonus(true);
    try {
      await processGiveawayClaimFirestore(currentUser.id, bonusCode);
      alert("Bonus successfully credited to your Profit Balance!");
      setBonusCode('');
    } catch (err: any) {
      alert(err.message || "Failed to claim bonus.");
    } finally {
      setIsClaimingBonus(false);
    }
  };

  const handlePurchaseRequest = (pkgId: string) => {
    if (!currentUser) return;
    const pkg = dynamicPackages.find(p => p.id === pkgId);
    if (!pkg) return;

    const currentActive = activePackages.find(p => p.isActive);
    let cost = pkg.minAmount;
    let action = "Deploy Node";

    if (currentActive) {
        if (currentActive.packageId === pkgId) return;
        if (currentActive.amount >= pkg.minAmount) {
            alert("No downgrades allowed.");
            return;
        }
        cost = pkg.minAmount - currentActive.amount;
        action = "Upgrade Node";
    }

    if (currentUser.capitalBalance < cost) {
      setPurchaseModal({ pkgId, name: pkg.name, cost, action: 'Insufficient Funds', type: 'INSUFFICIENT' });
    } else {
      setPurchaseModal({ pkgId, name: pkg.name, cost, action, type: 'PURCHASE' });
    }
  };

  const confirmPurchase = async () => {
    if (!purchaseModal || !currentUser) return;
    if (purchaseModal.type === 'INSUFFICIENT') {
      setView('wallet');
      setPurchaseModal(null);
      return;
    }
    setIsProcessingPurchase(true);
    try {
      await purchasePackageFirestore(currentUser.id, purchaseModal.pkgId, dynamicPackages);
      alert(`${purchaseModal.action} successful!`);
      setPurchaseModal(null);
    } catch (err: any) {
      alert(`Error: ${err.message}`);
    } finally {
      setIsProcessingPurchase(false);
    }
  };

  if (isLoading || (auth.currentUser && !currentUser)) {
    return (
      <div className="min-h-screen bg-app-bg flex items-center justify-center">
        <div className="flex flex-col items-center gap-6">
          <div className="w-12 h-12 border-4 border-app-border border-t-app-accent rounded-full animate-spin"></div>
          <p className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted animate-pulse">
            {isProvisioning ? 'Creating Account...' : 'Loading Protocol...'}
          </p>
        </div>
      </div>
    );
  }

  const displayUser = currentUser ? {
    ...currentUser,
    referralCount: myReferrals.length
  } : null;

  if (displayUser && platformSettings.platformPaused && !displayUser.isAdmin) {
    return <MaintenanceScreen onLogout={handleLogout} />;
  }

  if (!displayUser) {
    if (showLanding) {
      return (
        <LandingPage 
          onLogin={() => { setAuthMode('login'); setShowLanding(false); }} 
          onRegister={() => { setAuthMode('register'); setShowLanding(false); }} 
        />
      );
    }

    return (
      <div className="min-h-screen bg-app-bg flex flex-col lg:flex-row relative transition-colors duration-300">
        <div className="flex-1 p-12 lg:p-24 flex flex-col justify-between border-r border-app-border">
          <div className="flex items-center gap-4 cursor-pointer" onClick={() => setShowLanding(true)}>
             <div className="w-8 h-8 bg-app-accent"></div>
             <span className="text-2xl font-black uppercase tracking-tighter text-app-text">QUANTUM</span>
          </div>
          <div className="max-w-xl space-y-12">
            <motion.h1 
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="text-7xl lg:text-9xl font-black tracking-tighter leading-[0.85] uppercase text-app-text"
            >
              Start <br/> <span className="text-app-muted">Earning.</span>
            </motion.h1>
            <p className="serif italic text-2xl text-app-muted leading-relaxed">
              Professional USDT Staking Platform. Simple, secure, and profitable.
            </p>
          </div>
          <button 
            onClick={() => setShowLanding(true)}
            className="flex items-center gap-2 text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors"
          >
            <i className="fa-solid fa-arrow-left"></i>
            Back to Home
          </button>
        </div>
        <div className="w-full lg:w-[35%] min-h-screen bg-app-bg flex items-center justify-center p-12 lg:p-24 transition-colors duration-300">
          <motion.div initial={{ opacity: 0 }} animate={{ opacity: 1 }} className="w-full max-sm space-y-12">
            <div>
              <h2 className="text-[10px] font-black uppercase tracking-[0.5em] text-app-muted mb-2">Welcome</h2>
              <p className="text-2xl font-bold tracking-tight text-app-text">
                {authMode === 'login' ? 'Log In' : (authMode === 'register' ? 'Create Account' : 'Reset Password')}
              </p>
            </div>
            {authError && (
              <div className="p-4 bg-red-500/10 border border-red-500/20 text-red-500 text-[10px] font-bold uppercase tracking-widest">
                {authError}
              </div>
            )}
            <form className="space-y-8" onSubmit={(e) => {
              if (authMode === 'login') handleLogin(e);
              else if (authMode === 'register') handleRegister(e);
              else handlePasswordReset(e);
            }}>
              <div className="space-y-2 group">
                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Email</p>
                <input type="email" required value={email} onChange={(e) => setEmail(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="name@email.com" />
              </div>
              {authMode !== 'forgot-password' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-app-muted group-focus-within:text-app-text transition-colors">Password</p>
                  <div className="relative">
                    <input type={showPassword ? "text" : "password"} required value={password} onChange={(e) => setPassword(e.target.value)} className="w-full bg-transparent border-b border-app-border py-3 pr-8 outline-none focus:border-app-text transition-colors font-medium text-app-text placeholder:text-app-muted/30" placeholder="••••••••" />
                    <button type="button" onClick={() => setShowPassword(!showPassword)} className="absolute right-0 top-1/2 -translate-y-1/2 text-app-muted hover:text-app-text transition-colors p-2">
                      <i className={`fa-solid ${showPassword ? 'fa-eye-slash' : 'fa-eye'} text-xs`}></i>
                    </button>
                  </div>
                </div>
              )}
              {authMode === 'register' && (
                <div className="space-y-2 group">
                  <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Referral Code (Optional)</p>
                  <input type="text" value={refCode} onChange={(e) => setRefCode(e.target.value.toUpperCase())} className="w-full bg-transparent border-b border-app-border py-3 outline-none focus:border-app-text transition-colors font-mono text-xs uppercase text-app-text placeholder:text-app-muted/30" placeholder="CODE" />
                </div>
              )}
              <button type="submit" disabled={isLoading} className="w-full py-5 bg-app-accent text-app-accent-text text-xs font-black uppercase tracking-[0.3em] hover:opacity-90 transition-all flex items-center justify-center gap-4">
                {isLoading ? <div className="w-4 h-4 border-2 border-app-accent-text/20 border-t-app-accent-text rounded-full animate-spin"></div> : (authMode === 'login' ? 'Log In' : (authMode === 'register' ? 'Sign Up' : 'Send Reset Link'))}
              </button>
              <div className="text-center pt-4">
                 <button type="button" onClick={() => { setAuthMode(authMode === 'login' ? 'register' : 'login'); setAuthError(null); }} className="text-[10px] font-black uppercase tracking-widest text-app-muted hover:text-app-text transition-colors">
                   {authMode === 'login' ? "Create an Account" : "Back to Login"}
                 </button>
              </div>
            </form>
          </motion.div>
        </div>
      </div>
    );
  }

  return (
    <Layout user={displayUser} onLogout={handleLogout} onNavigate={setView} currentView={view}>
      <AnimatePresence mode="wait">
        <motion.div key={view} initial={{ opacity: 0, y: 5 }} animate={{ opacity: 1, y: 0 }} exit={{ opacity: 0, y: -5 }} transition={{ duration: 0.3 }} className="pb-24 lg:pb-0">
          {view === 'dashboard' && (
            <div className="space-y-16">
              <Dashboard user={displayUser} transactions={transactions} activePackages={activePackages} />

              {/* Bonus Code UI on Dashboard */}
              <div className="max-w-xl">
                 <div className="p-10 border border-app-border bg-app-surface space-y-6">
                    <div>
                       <h3 className="text-xs font-black uppercase tracking-[0.4em] text-app-text mb-1">Protocol Uplink</h3>
                       <p className="text-[10px] font-bold text-app-muted uppercase tracking-widest">Enter bonus or giveaway codes below</p>
                    </div>
                    <form onSubmit={handleBonusClaim} className="flex gap-px bg-app-border border border-app-border overflow-hidden">
                       <input 
                        type="text" 
                        value={bonusCode}
                        onChange={(e) => setBonusCode(e.target.value.toUpperCase())}
                        placeholder="ENTER CODE"
                        className="flex-1 bg-app-bg px-6 py-4 outline-none text-sm font-black mono tracking-widest uppercase text-app-text placeholder:text-app-muted/20"
                       />
                       <button 
                        type="submit" 
                        disabled={isClaimingBonus || !bonusCode.trim()}
                        className="bg-app-accent text-app-accent-text px-8 py-4 text-[10px] font-black uppercase tracking-widest hover:opacity-90 transition-all disabled:opacity-50"
                       >
                         {isClaimingBonus ? 'Linking...' : 'Claim'}
                       </button>
                    </form>
                 </div>
              </div>
            </div>
          )}
          {view === 'wallet' && (
            <Wallet 
              user={displayUser} 
              paymentSettings={paymentSettings} 
              onDepositSim={handleDepositSync} 
              onWithdrawRequest={handleWithdrawal} 
            />
          )}
          {view === 'packages' && (
            <div className="space-y-12 max-w-7xl mx-auto">
               <div className="flex flex-col gap-4">
                  <h2 className="text-5xl lg:text-9xl font-black uppercase tracking-tighter leading-none text-app-text">Liquidity<br/>Nodes.</h2>
                  <p className="serif italic text-xl lg:text-2xl text-app-muted max-w-xl">Rent high-performance computing power to generate USDT.</p>
               </div>
               <div className="grid grid-cols-2 md:grid-cols-3 border-t border-l border-app-border">
                 {dynamicPackages.filter(p => p.isActive !== false).map((pkg) => {
                   const currentActive = activePackages.find(ap => ap.isActive);
                   const isCurrent = currentActive?.packageId === pkg.id;
                   let isDisabled = false;
                   let buttonText = "Deploy Node";
                   let extraInfo = "";
                   let isLocked = false;
                   let cost = pkg.minAmount;

                   if (currentActive) {
                      if (isCurrent) { buttonText = "Node Active"; isDisabled = true; } 
                      else if (pkg.minAmount <= currentActive.amount) { buttonText = "Unavailable"; isDisabled = true; extraInfo = "No downgrades"; } 
                      else {
                          const upgradeCost = pkg.minAmount - currentActive.amount;
                          cost = upgradeCost;
                          if (displayUser.capitalBalance < cost) { isLocked = true; isDisabled = true; buttonText = "Locked"; } 
                          else { buttonText = "Upgrade Available"; extraInfo = `Pay: ${upgradeCost.toFixed(0)} USDT`; }
                      }
                   } else if (displayUser.capitalBalance < cost) { isLocked = true; isDisabled = true; buttonText = "Locked"; }

                   return (
                     <div key={pkg.id} className={`border-r border-b border-app-border p-6 md:p-12 group transition-all duration-500 relative ${isDisabled && !isLocked ? 'opacity-50 grayscale' : ''} ${!isDisabled ? 'hover:bg-app-accent hover:text-app-accent-text' : ''}`}>
                       {isLocked && (
                         <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-app-bg/5 backdrop-blur-[2px]">
                            <div className="w-16 h-16 rounded-full bg-app-bg border border-app-border flex items-center justify-center shadow-xl mb-4"><i className="fa-solid fa-lock text-xl text-app-muted"></i></div>
                            <div className="px-3 py-1 bg-app-bg border border-app-border text-[8px] font-black uppercase tracking-widest text-app-muted">Unlock: ${cost.toFixed(0)}</div>
                         </div>
                       )}
                       <div className={`space-y-4 md:space-y-8 h-full flex flex-col ${isLocked ? 'opacity-30 blur-[1px]' : ''}`}>
                         <div className="flex justify-between items-start">
                           <h3 className="text-[10px] md:text-xs font-black uppercase tracking-[0.2em]">{pkg.name}</h3>
                           {isCurrent && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-green-500 text-white">Online</span>}
                         </div>
                         <div className="space-y-1">
                           <p className="text-3xl md:text-6xl font-black mono tracking-tighter leading-none">${(pkg.minAmount * pkg.dailyRoi / 100).toFixed(2)}</p>
                           <p className="text-[8px] font-black uppercase tracking-widest opacity-60">Daily Return</p>
                         </div>
                         <p className="text-[10px] md:text-sm font-medium opacity-60 group-hover:opacity-100">{pkg.description}</p>
                         <div className="mt-auto space-y-4 pt-6">
                           <div className="flex justify-between border-b border-app-border group-hover:border-app-accent-text/10">
                             <span className="text-[8px] font-bold uppercase opacity-60">Lease Cost</span>
                             <span className="text-[10px] font-bold mono">${pkg.minAmount}</span>
                           </div>
                           <button onClick={() => !isDisabled && handlePurchaseRequest(pkg.id)} disabled={isDisabled} className={`w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-app-border flex items-center justify-center gap-2 ${!isDisabled ? 'group-hover:bg-app-accent-text group-hover:text-app-accent group-hover:border-app-accent-text' : ''}`}>
                            {buttonText}
                           </button>
                           {extraInfo && <p className="text-[9px] font-bold uppercase text-center opacity-70">{extraInfo}</p>}
                         </div>
                       </div>
                     </div>
                   );
                 })}
               </div>
            </div>
          )}
          {view === 'referrals' && (
            <div className="space-y-24 max-w-7xl mx-auto">
               <div className="flex flex-col lg:flex-row justify-between items-end gap-12">
                  <div className="space-y-6 flex-1">
                    <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">Referral<br/>Program.</h1>
                    <p className="serif italic text-2xl text-app-muted max-w-xl">Earn rewards by inviting friends to the platform.</p>
                  </div>
                  <div className="w-full lg:w-96 p-10 bg-app-accent text-app-accent-text space-y-6">
                    <p className="text-[10px] font-black uppercase tracking-widest">Your Invite Code</p>
                    <p className="text-xl font-black mono tracking-widest truncate">{displayUser.referralCode}</p>
                    <button onClick={() => { navigator.clipboard.writeText(displayUser.referralCode); alert('Copied.'); }} className="w-full py-3 bg-app-accent-text text-app-accent text-[10px] font-black uppercase tracking-[0.2em]">Copy Code</button>
                  </div>
               </div>
               <div className="space-y-8">
                  <div className="flex items-center justify-between border-b border-app-border pb-4">
                    <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">My Downline</h2>
                    <span className="text-[10px] font-bold text-app-muted uppercase tracking-widest">{myReferrals.length} Partners</span>
                  </div>
                  <div className="border border-app-border bg-app-bg">
                    {myReferrals.length === 0 ? (
                      <div className="p-20 text-center opacity-20 serif italic text-app-muted">No partners yet.</div>
                    ) : (
                      <div className="grid grid-cols-1 divide-y divide-app-border">
                        {myReferrals.map((refUser, idx) => (
                          <div key={refUser.userId} className="p-6 flex items-center justify-between hover:bg-app-surface transition-colors">
                            <div className="flex items-center gap-6">
                               <span className="text-[10px] mono text-app-muted">{(idx + 1).toString().padStart(2, '0')}</span>
                               <div className="space-y-1">
                                  <p className="text-sm font-bold text-app-text">{refUser.email}</p>
                                  <p className="text-[10px] mono text-app-muted opacity-50">ID: {refUser.userId.slice(0,6).toUpperCase()}</p>
                               </div>
                            </div>
                            <div className="text-right">
                               <p className="text-[10px] font-black uppercase tracking-widest text-app-muted opacity-60">Earned</p>
                               <p className="text-sm font-bold mono text-green-500">+${(refUser.totalCommissions || 0).toFixed(2)}</p>
                            </div>
                          </div>
                        ))}
                      </div>
                    )}
                  </div>
               </div>
            </div>
          )}
          {view === 'profile' && <Profile user={displayUser} onUpdate={(data) => updateUserProfileFirestore(displayUser.id, data)} />}
          {view === 'admin' && (
            <AdminPanel 
              state={{ 
                currentUser: displayUser, 
                users: [], 
                packages: dynamicPackages, 
                activePackages, 
                transactions, 
                platformSettings,
                giveawayPools,
                paymentSettings
              }}
              onUpdateSettings={(s) => updatePlatformSettingsFirestore(s)}
              onTriggerRoi={async () => { 
                try {
                  await processDailyRoiFirestore(platformSettings, dynamicPackages); 
                  alert('Rewards paid.'); 
                } catch (err: any) { alert(`ROI Failed: ${err?.message}`); }
              }}
              onManageWithdrawal={() => {}}
            />
          )}
        </motion.div>
      </AnimatePresence>
      {purchaseModal && (
        <div className="fixed inset-0 bg-black/80 backdrop-blur-sm flex items-center justify-center z-[100] p-6">
          <motion.div initial={{ scale: 0.9, opacity: 0 }} animate={{ scale: 1, opacity: 1 }} className="bg-app-bg border border-app-border p-8 w-full max-w-md space-y-8 shadow-2xl">
             <div className="space-y-2">
               <h3 className="text-xl font-black uppercase tracking-tighter text-app-text">{purchaseModal.type === 'INSUFFICIENT' ? 'Deposit Required' : 'Confirm Deployment'}</h3>
               <p className="text-xs font-bold text-app-muted">{purchaseModal.type === 'INSUFFICIENT' ? 'Insufficient balance.' : `Deploying ${purchaseModal.name}`}</p>
             </div>
             <div className="py-6 border-y border-app-border space-y-4">
                <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase tracking-widest text-app-muted">Cost</span><span className="text-lg font-black mono text-app-text">${purchaseModal.cost.toFixed(2)}</span></div>
                <div className="flex justify-between items-center"><span className="text-[10px] font-black uppercase tracking-widest text-app-muted">Balance</span><span className={`text-lg font-black mono ${purchaseModal.type === 'INSUFFICIENT' ? 'text-red-500' : 'text-green-500'}`}>${displayUser.capitalBalance.toFixed(2)}</span></div>
             </div>
             <div className="flex gap-4">
                <button onClick={() => setPurchaseModal(null)} className="flex-1 py-3 border border-app-border text-[10px] font-black uppercase tracking-widest text-app-muted">Cancel</button>
                <button onClick={confirmPurchase} disabled={isProcessingPurchase} className={`flex-1 py-3 text-[10px] font-black uppercase tracking-widest transition-all ${purchaseModal.type === 'INSUFFICIENT' ? 'bg-app-text text-app-bg' : 'bg-app-accent text-app-accent-text'}`}>
                  {isProcessingPurchase ? 'Processing...' : (purchaseModal.type === 'INSUFFICIENT' ? 'Go to Wallet' : 'Confirm')}
                </button>
             </div>
          </motion.div>
        </div>
      )}
      <GuideModal isOpen={showGuide} onClose={() => setShowGuide(false)} />
    </Layout>
  );
};

const App: React.FC = () => (
  <ThemeProvider>
    <AppContent />
  </ThemeProvider>
);

export default App;

import React, { useState, useEffect, useRef } from 'react';
import { User, TransactionStatus, TransactionType, PaymentSettings } from '../types.ts';
import { QRCodeCanvas } from 'qrcode.react';
import { processExternalDeposit } from '../store.ts';

interface WalletProps {
  user: User;
  paymentSettings?: PaymentSettings;
  onDepositSim: () => void;
  onWithdrawRequest: (amount: number, address: string) => void;
}

const Wallet: React.FC<WalletProps> = ({ user, paymentSettings, onDepositSim, onWithdrawRequest }) => {
  const [withdrawAmount, setWithdrawAmount] = useState('');
  const [withdrawAddress, setWithdrawAddress] = useState(user.withdrawalAddress || '');
  const [isSyncing, setIsSyncing] = useState(false);

  // Payment Gateway State
  const [depositAmount, setDepositAmount] = useState<string>('');
  const [activePayment, setActivePayment] = useState<any>(null);
  const [paymentStatus, setPaymentStatus] = useState<string>('waiting'); // waiting, confirming, confirmed, expired
  const [isGeneratingPayment, setIsGeneratingPayment] = useState(false);
  const [paymentError, setPaymentError] = useState<string | null>(null);

  // Refs for polling management
  const pollTimeoutRef = useRef<number | null>(null);
  const isMounted = useRef(true);

  const usePaymentGateway = paymentSettings?.isEnabled;

  useEffect(() => {
    return () => { isMounted.current = false; stopPolling(); };
  }, []);

  const stopPolling = () => {
    if (pollTimeoutRef.current) {
        clearTimeout(pollTimeoutRef.current);
        pollTimeoutRef.current = null;
    }
  };

  const handleManualSync = async () => {
    setIsSyncing(true);
    await onDepositSim();
    setIsSyncing(false);
  };

  const generatePayment = async () => {
    const amount = parseFloat(depositAmount);
    if (!amount || amount <= 0 || !paymentSettings?.apiKey) {
        setPaymentError("Invalid amount or missing API configuration.");
        return;
    }

    setIsGeneratingPayment(true);
    setPaymentError(null);
    setPaymentStatus('waiting');

    try {
        // Using corsproxy.io to bypass CORS restriction in client-side only mode
        // In a full production server environment, this call should be made from your backend.
        const proxyUrl = 'https://corsproxy.io/?';
        const targetUrl = 'https://api.nowpayments.io/v1/payment';

        const response = await fetch(proxyUrl + encodeURIComponent(targetUrl), {
            method: 'POST',
            headers: {
                'x-api-key': paymentSettings.apiKey,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify({
                price_amount: amount,
                price_currency: 'usd',
                pay_currency: 'usdttrc20', // Enforced TRC20
                order_description: `Deposit User:${user.id}`,
                ipn_callback_url: '' // Optional: Add if you deploy a backend function
            })
        });

        if (!response.ok) {
            const errData = await response.json().catch(() => ({}));
            throw new Error(errData.message || `API Error: ${response.statusText}`);
        }

        const data = await response.json();

        if (data.pay_address && data.payment_id) {
            setActivePayment(data);
            // Start polling immediately
            pollStatus(data.payment_id);
        } else {
            setPaymentError("Gateway failed to generate address. Please try again.");
        }
    } catch (err: any) {
        console.error("Payment Gen Error:", err);
        setPaymentError(err.message || "Connection failed. Please check your internet.");
    } finally {
        if(isMounted.current) setIsGeneratingPayment(false);
    }
  };

  const pollStatus = async (paymentId: string) => {
    if (!isMounted.current) return;

    try {
        const proxyUrl = 'https://corsproxy.io/?';
        const targetUrl = `https://api.nowpayments.io/v1/payment/${paymentId}`;

        const res = await fetch(proxyUrl + encodeURIComponent(targetUrl), {
            headers: { 'x-api-key': paymentSettings!.apiKey }
        });

        if (!res.ok) throw new Error("Status check failed");

        const data = await res.json();
        const status = data.payment_status;

        if(isMounted.current) setPaymentStatus(status);

        // Status Logic
        // finished: Success
        // confirmed: Funds on blockchain, aggregating
        // sending: Sending to your wallet
        // partially_paid: User sent funds but less than requested (Still credit them)
        if (['finished', 'confirmed', 'sending'].includes(status)) {
            await handlePaymentSuccess(data);
            return; // Stop polling
        }

        if (status === 'expired' || status === 'failed') {
            setPaymentError("Transaction expired or failed. Please create a new deposit.");
            stopPolling();
            return;
        }

        // Continue polling if waiting/confirming
        pollTimeoutRef.current = window.setTimeout(() => pollStatus(paymentId), 5000);

    } catch (e) { 
        console.debug("Poll failed (retrying...):", e); 
        // Retry on error
        pollTimeoutRef.current = window.setTimeout(() => pollStatus(paymentId), 5000);
    }
  };

  const handlePaymentSuccess = async (data: any) => {
    stopPolling();

    try {
        // Use pay_amount (actual) if available, else price_amount
        const verifiedAmount = data.pay_amount || data.price_amount || parseFloat(depositAmount); 

        await processExternalDeposit(user.id, verifiedAmount, data.payment_id);

        alert(`Deposit of ${verifiedAmount} USDT confirmed successfully!`);

        if(isMounted.current) {
            setActivePayment(null);
            setDepositAmount('');
            setPaymentStatus('waiting');
        }
    } catch (e) {
        console.error("Credit error", e);
        setPaymentError("Payment confirmed but failed to update balance. Contact support with ID: " + data.payment_id);
    }
  };

  const getStatusDisplay = () => {
    switch(paymentStatus) {
        case 'waiting': return { text: 'Waiting for Funds...', color: 'text-app-muted', icon: 'fa-spinner fa-spin' };
        case 'confirming': return { text: 'Confirming on Blockchain...', color: 'text-blue-500', icon: 'fa-circle-notch fa-spin' };
        case 'confirmed': 
        case 'sending':
        case 'finished': return { text: 'Payment Successful!', color: 'text-green-500', icon: 'fa-check-circle' };
        case 'expired': return { text: 'Expired', color: 'text-red-500', icon: 'fa-times-circle' };
        default: return { text: paymentStatus.toUpperCase(), color: 'text-app-text', icon: 'fa-info-circle' };
    }
  };

  const statusInfo = getStatusDisplay();

  return (
    <div className="max-w-7xl mx-auto space-y-24 pb-24 lg:pb-0">
      <div className="flex flex-col gap-4">
        <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">My<br/>Wallet.</h1>
        <p className="serif italic text-2xl text-app-muted max-w-xl">
          Deposit USDT (TRC20) to fund your account or withdraw your profits.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-px bg-app-border border border-app-border">

        {/* Deposit Section */}
        <div className="bg-app-bg p-12 lg:p-20 space-y-12">
          <div className="flex items-center justify-between">
            <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">
                {usePaymentGateway ? 'Deposit Gateway' : 'Deposit USDT'}
            </h2>
            <span className="text-[10px] px-2 py-0.5 border border-app-border font-bold uppercase text-green-500">TRC20 Network</span>
          </div>

          {usePaymentGateway ? (
            // NowPayments Flow
            <div className="space-y-8">
                {!activePayment ? (
                    <div className="space-y-6">
                        <div className="p-6 bg-app-surface border border-app-border space-y-2">
                           <p className="text-[10px] font-black uppercase text-app-muted tracking-widest">Secure Payment</p>
                           <p className="text-xs text-app-text/60 leading-relaxed font-medium">
                               Enter the amount you wish to deposit. Our gateway will generate a unique, one-time secure payment address for you.
                           </p>
                        </div>
                        <div className="space-y-2 group">
                            <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Amount (USD)</label>
                            <input 
                                type="number" 
                                value={depositAmount} 
                                onChange={(e) => setDepositAmount(e.target.value)}
                                className="w-full bg-transparent border-b border-app-border py-4 text-4xl font-black mono text-app-text outline-none focus:border-app-accent transition-colors"
                                placeholder="100.00"
                            />
                        </div>
                        {paymentError && <p className="text-xs text-red-500 font-bold uppercase animate-pulse">{paymentError}</p>}
                        <button 
                            onClick={generatePayment}
                            disabled={isGeneratingPayment || !depositAmount}
                            className="w-full py-6 bg-app-accent text-app-accent-text text-[10px] font-black uppercase tracking-[0.4em] hover:opacity-90 transition-all flex items-center justify-center gap-4 disabled:opacity-50"
                        >
                            {isGeneratingPayment ? 'Generating...' : 'Deposit Funds'}
                        </button>
                    </div>
                ) : (
                    <div className="flex flex-col items-center gap-8 py-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
                        {/* Status Bar */}
                        <div className={`w-full p-4 border border-app-border flex items-center justify-center gap-3 ${paymentStatus === 'expired' ? 'bg-red-500/10' : 'bg-app-surface'}`}>
                            <i className={`fa-solid ${statusInfo.icon} ${statusInfo.color}`}></i>
                            <span className={`text-xs font-black uppercase tracking-widest ${statusInfo.color}`}>{statusInfo.text}</span>
                        </div>

                        {paymentStatus !== 'expired' && (
                            <div className="bg-white p-4 relative shadow-2xl">
                               <QRCodeCanvas 
                                  value={activePayment.pay_address}
                                  size={200}
                                  level={"H"}
                               />
                               <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
                                  <div className="w-10 h-10 bg-white rounded-full flex items-center justify-center shadow-lg">
                                     <i className="fa-solid fa-bolt text-black text-xl"></i>
                                  </div>
                               </div>
                            </div>
                        )}

                        <div className="w-full text-center space-y-6">
                           <div className="space-y-1">
                                <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Send Exactly</p>
                                <p className="text-4xl font-black mono text-app-text">{activePayment.pay_amount} USDT</p>
                           </div>

                           {paymentStatus !== 'expired' && (
                               <div className="space-y-2">
                                   <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">To Address (TRC20)</p>
                                   <p 
                                    onClick={() => { navigator.clipboard.writeText(activePayment.pay_address); alert('Address Copied!'); }}
                                    className="text-xs mono break-all text-app-text border border-app-border p-4 hover:border-app-text transition-colors cursor-pointer bg-app-surface select-all flex items-center justify-between gap-4 text-left"
                                   >
                                     <span>{activePayment.pay_address}</span>
                                     <i className="fa-regular fa-copy"></i>
                                   </p>
                               </div>
                           )}

                           <div className="grid grid-cols-2 gap-4">
                               <button 
                                 onClick={() => pollStatus(activePayment.payment_id)} 
                                 className="py-3 border border-app-border text-[9px] font-black uppercase hover:bg-app-surface"
                               >
                                 <i className="fa-solid fa-rotate-right mr-2"></i>
                                 Check Status
                               </button>
                               <button 
                                 onClick={() => { stopPolling(); setActivePayment(null); }} 
                                 className="py-3 border border-app-border text-[9px] font-black uppercase hover:bg-red-500 hover:text-white hover:border-red-500 transition-colors"
                               >
                                 Cancel Order
                               </button>
                           </div>

                           <p className="text-[8px] text-app-muted uppercase font-bold opacity-50">
                             ID: {activePayment.payment_id}
                           </p>
                        </div>
                    </div>
                )}
            </div>
          ) : (
            // Manual Deposit Flow (Fallback)
            <div className="space-y-8">
              <div className="bg-white p-4 w-fit mx-auto relative group">
                <QRCodeCanvas value={user.usdtDepositAddress} size={200} level={"H"} />
              </div>
              <div className="space-y-4 text-center">
                 <p className="text-[10px] font-black uppercase tracking-[0.2em] text-app-muted">Your Wallet Address</p>
                 <div className="relative group cursor-pointer" onClick={() => { navigator.clipboard.writeText(user.usdtDepositAddress); alert('Address copied!'); }}>
                   <p className="text-xs sm:text-sm font-bold mono break-all border border-app-border p-4 hover:border-app-accent transition-colors bg-app-surface select-all">
                     {user.usdtDepositAddress}
                   </p>
                 </div>
                 <p className="text-[10px] text-app-muted max-w-sm mx-auto leading-relaxed">
                   Send only USDT (TRC20) to this address. Sending any other asset may result in permanent loss.
                 </p>
              </div>
              <button 
                onClick={handleManualSync} 
                disabled={isSyncing}
                className="w-full py-6 border border-app-border text-[10px] font-black uppercase tracking-[0.4em] hover:bg-app-text hover:text-app-bg transition-all flex items-center justify-center gap-2 disabled:opacity-50"
              >
                {isSyncing ? <div className="w-3 h-3 border-2 border-app-text/30 border-t-app-text rounded-full animate-spin"/> : 'Check for Deposit'}
              </button>
            </div>
          )}
        </div>

        {/* Withdrawal Section */}
        <div className="bg-app-surface p-12 lg:p-20 space-y-12">
          <div className="flex items-center justify-between">
            <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">Withdraw Funds</h2>
            <span className="text-[10px] px-2 py-0.5 border border-app-border font-bold uppercase text-app-muted">Profit Balance</span>
          </div>

          <div className="space-y-8">
            <div className="space-y-2">
               <p className="text-[10px] font-black uppercase tracking-widest text-app-muted">Available</p>
               <p className="text-5xl font-black mono text-app-text">${user.profitBalance.toFixed(2)}</p>
            </div>

            <div className="space-y-6">
              <div className="space-y-2 group">
                <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Amount</label>
                <input 
                  type="number" 
                  value={withdrawAmount} 
                  onChange={(e) => setWithdrawAmount(e.target.value)}
                  className="w-full bg-transparent border-b border-app-border py-4 text-2xl font-black mono text-app-text outline-none focus:border-app-accent transition-colors"
                  placeholder="0.00"
                />
              </div>
              <div className="space-y-2 group">
                <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Destination Address (TRC20)</label>
                <input 
                  type="text" 
                  value={withdrawAddress} 
                  onChange={(e) => setWithdrawAddress(e.target.value)}
                  className="w-full bg-transparent border-b border-app-border py-4 text-xs font-mono text-app-text outline-none focus:border-app-accent transition-colors"
                  placeholder="Enter TRC20 address..."
                />
              </div>
            </div>

            <button 
              onClick={() => {
                 const amt = parseFloat(withdrawAmount);
                 if (!amt || amt <= 0 || !withdrawAddress) {
                    alert("Please enter valid amount and address");
                    return;
                 }
                 onWithdrawRequest(amt, withdrawAddress);
                 setWithdrawAmount('');
              }}
              className="w-full py-6 bg-app-text text-app-bg text-[10px] font-black uppercase tracking-[0.4em] hover:bg-app-accent hover:text-app-accent-text transition-all"
            >
              Request Payout
            </button>
          </div>
        </div>

      </div>
    </div>
  );
};

export default Wallet;

import React, { useState, useEffect, useRef } from 'react';
import { User, TransactionStatus, TransactionType, PaymentSettings } from '../types.ts';
import { QRCodeCanvas } from 'qrcode.react';
import { processExternalDeposit } from '../store.ts';

interface WalletProps {
  user: User;
  paymentSettings?: PaymentSettings;
  onDepositSim: () => void;
  onWithdrawRequest: (amount: number, address: string) => void;
}

const Wallet: React.FC<WalletProps> = ({ user, paymentSettings, onDepositSim, onWithdrawRequest }) => {
  const [withdrawAmount, setWithdrawAmount] = useState('');
  const [withdrawAddress, setWithdrawAddress] = useState(user.withdrawalAddress || '');
  const [isSyncing, setIsSyncing] = useState(false);

  // Payment Gateway State
  const [depositAmount, setDepositAmount] = useState<string>('');
  const [activePayment, setActivePayment] = useState<any>(null);
  const [paymentStatus, setPaymentStatus] = useState<string>('waiting'); // waiting, confirming, confirmed, expired
  const [isGeneratingPayment, setIsGeneratingPayment] = useState(false);
  const [paymentError, setPaymentError] = useState<string | null>(null);

  // Refs for polling management
  const pollTimeoutRef = useRef<number | null>(null);
  const isMounted = useRef(true);

  const usePaymentGateway = paymentSettings?.isEnabled;

  useEffect(() => {
    return () => { isMounted.current = false; stopPolling(); };
  }, []);

  const stopPolling = () => {
    if (pollTimeoutRef.current) {
        clearTimeout(pollTimeoutRef.current);
        pollTimeoutRef.current = null;
    }
  };

  const handleManualSync = async () => {
    setIsSyncing(true);
    await onDepositSim();
    setIsSyncing(false);
  };

  const generatePayment = async () => {
    const amount = parseFloat(depositAmount);
    if (!amount || amount <= 0 || !paymentSettings?.apiKey) {
        setPaymentError("Invalid amount or missing API configuration.");
        return;
    }

    setIsGeneratingPayment(true);
    setPaymentError(null);
    setPaymentStatus('waiting');

    try {
        const proxyUrl = 'https://corsproxy.io/?';
        const targetUrl = 'https://api.nowpayments.io/v1/payment';

        // Construct payload dynamically to avoid sending empty fields that the API rejects
        const payload: any = {
            price_amount: amount,
            price_currency: 'usd',
            pay_currency: 'usdttrc20', // Enforced TRC20
            order_description: `Deposit User:${user.id}`
        };

        // Only include IPN URL if strictly necessary and available. 
        // For client-side only demos, we usually omit it to avoid "not allowed to be empty" error.
        // If a backend url is configured in settings, we use it.
        // Note: The error "ipn_callback_url is not allowed to be empty" implies we should either provide a valid URL or remove the key.
        // We remove the key here.

        const response = await fetch(proxyUrl + encodeURIComponent(targetUrl), {
            method: 'POST',
            headers: {
                'x-api-key': paymentSettings.apiKey,
                'Content-Type': 'application/json'
            },
            body: JSON.stringify(payload)
        });

        if (!response.ok) {
            const errData = await response.json().catch(() => ({}));
            throw new Error(errData.message || `API Error: ${response.statusText}`);
        }

        const data = await response.json();

        if (data.pay_address && data.payment_id) {
            setActivePayment(data);
            // Start polling immediately
            pollStatus(data.payment_id);
        } else {
            setPaymentError("Gateway failed to generate address. Please try again.");
        }
    } catch (err: any) {
        console.error("Payment Gen Error:", err);
        setPaymentError(err.message || "Connection failed. Please check your internet.");
    } finally {
        if(isMounted.current) setIsGeneratingPayment(false);
    }
  };

  const pollStatus = async (paymentId: string) => {
    if (!isMounted.current) return;

    try {
        const proxyUrl = 'https://corsproxy.io/?';
        const targetUrl = `https://api.nowpayments.io/v1/payment/${paymentId}`;

        const res = await fetch(proxyUrl + encodeURIComponent(targetUrl), {
            headers: { 'x-api-key': paymentSettings!.apiKey }
        });

        if (!res.ok) throw new Error("Status check failed");

        const data = await res.json();
        const status = data.payment_status;

        if(isMounted.current) setPaymentStatus(status);

        // Status Logic
        // finished: Success
        // confirmed: Funds on blockchain, aggregating
        // sending: Sending to your wallet
        // partially_paid: User sent funds but less than requested (Still credit them)
        if (['finished', 'confirmed', 'sending'].includes(status)) {
            await handlePaymentSuccess(data);
            return; // Stop polling
        }

        if (status === 'expired' || status === 'failed') {
            setPaymentError("Transaction expired or failed. Please create a new deposit.");
            stopPolling();
            return;
        }

        // Continue polling if waiting/confirming
        pollTimeoutRef.current = window.setTimeout(() => pollStatus(paymentId), 5000);

    } catch (e) { 
        console.debug("Poll failed (retrying...):", e); 
        // Retry on error
        pollTimeoutRef.current = window.setTimeout(() => pollStatus(paymentId), 5000);
    }
  };

  const handlePaymentSuccess = async (data: any) => {
    stopPolling();

    try {
        // Use pay_amount (actual) if available, else price_amount
        const verifiedAmount = data.pay_amount || data.price_amount || parseFloat(depositAmount); 

        await processExternalDeposit(user.id, verifiedAmount, data.payment_id);

        alert(`Deposit of ${verifiedAmount} USDT confirmed successfully!`);

        if(isMounted.current) {
            setActivePayment(null);
            setDepositAmount('');
            setPaymentStatus('waiting');
        }
    } catch (e) {
        console.error("Credit error", e);
        setPaymentError("Payment confirmed but failed to update balance. Contact support with ID: " + data.payment_id);
    }
  };

  const getStatusDisplay = () => {
    switch(paymentStatus) {
        case 'waiting': return { text: 'Waiting for Funds...', color: 'text-app-muted', icon: 'fa-spinner fa-spin' };
        case 'confirming': return { text: 'Confirming on Blockchain...', color: 'text-blue-500', icon: 'fa-circle-notch fa-spin' };
        case 'confirmed': 
        case 'sending':
        case 'finished': return { text: 'Payment Successful!', color: 'text-green-500', icon: 'fa-check-circle' };
        case 'expired': return { text: 'Expired', color: 'text-red-500', icon: 'fa-times-circle' };
        default: return { text: paymentStatus.toUpperCase(), color: 'text-app-text', icon: 'fa-info-circle' };
    }
  };

  const statusInfo = getStatusDisplay();

  return (
    <div className="max-w-7xl mx-auto space-y-24 pb-24 lg:pb-0">
      <div className="flex flex-col gap-4">
        <h1 className="text-6xl lg:text-9xl font-black uppercase tracking-tighter leading-[0.85] text-app-text">My<br/>Wallet.</h1>
        <p className="serif italic text-2xl text-app-muted max-w-xl">
          Deposit USDT (TRC20) to fund your account or withdraw your profits.
        </p>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-px bg-app-border border border-app-border">

        {/* Deposit Section */}
        <div className="bg-app-bg p-12 lg:p-20 space-y-12">
          <div className="flex items-center justify-between">
            <h2 className="text-xs font-black uppercase tracking-[0.4em] text-app-text">
                {usePaymentGateway ? 'Deposit Gateway' : 'Deposit USDT'}
            </h2>
            <span className="text-[10px] px-2 py-0.5 border border-app-border font-bold uppercase text-green-500">TRC20 Network</span>
          </div>

          {usePaymentGateway ? (
            // NowPayments Flow
            <div className="space-y-8">
                {!activePayment ? (
                    <div className="space-y-6">
                        <div className="p-6 bg-app-surface border border-app-border space-y-2">
                           <p className="text-[10px] font-black uppercase text-app-muted tracking-widest">Secure Payment</p>
                           <p className="text-xs text-app-text/60 leading-relaxed font-medium">
                               Enter the amount you wish to deposit. Our gateway will generate a unique, one-time secure payment address for you.
                           </p>
                        </div>
                        <div className="space-y-2 group">
                            <label className="text-[10px] font-black uppercase tracking-widest text-app-muted">Amount (USD)</label>
                            <input 
                                type="number" 
                                value={depositAmount} 
                                onChange={(e) => setDepositAmount(e.target.value)}
                                className="w-full bg-transparent border-b border-app-border py-4 text-4xl font-black mono text-app-text outline-none focus:border-app-accent transition-colors"
                                placeholder="100.00"
                            />
                        </div>
                        {paymentError && <p className="text-xs text-red-500 font-bold uppercase animate-pulse">{paymentError}</p>}
                        <button 
                            onClick={generatePayment}
                            disabled={isGeneratingPayment || !depositAmount}
                            className="w-full py-6 bg-app-accent text-app-accent-text text-[10px] font-black uppercase tracking-[0.4em] hover:opacity-90 transition-all flex items-center justify-center gap-4 disabled:opacity-50"
                        >
                            {isGeneratingPayment ? 'Generating...' : 'Deposit Funds'}
                        </button>
                    </div>
                ) : (
                    <div className="flex flex-col items-center gap-8 py-4 animate-in fade-in slide-in-from-bottom-4 duration-500">
