// Updated sanitization logic to match App.tsx and prevent circular JSON errors.
const sanitizeDoc = (docSnap: any) => {
    const data = docSnap.data();
    if (!data) return { id: docSnap.id };

    const clean: any = { id: docSnap.id };

    Object.keys(data).forEach(key => {
        const val = data[key];

        if (!val) {
            clean[key] = val;
            return;
        }

        if (typeof val.toMillis === 'function') {
            clean[key] = val.toMillis();
        }
        else if (typeof val === 'object' && typeof val.path === 'string' && typeof val.id === 'string') {
             clean[key] = val.path;
        }
        else if (Array.isArray(val)) {
            clean[key] = val.map((item: any) => {
                if (item && typeof item.toMillis === 'function') return item.toMillis();
                if (item && typeof item.path === 'string' && typeof item.id === 'string') return item.path;
                return item;
            });
        }
        else if (typeof val === 'object') {
             if ('firestore' in val || '_key' in val || 'converter' in val) {
                 clean[key] = null;
             } else {
                 try {
                     if (Object.prototype.toString.call(val) === '[object Object]') {
                         clean[key] = { ...val };
                     } else {
                         clean[key] = null;
                     }
                 } catch(e) {
                     clean[key] = null;
                 }
             }
        }
        else {
            clean[key] = val;
        }
    });
    return clean;
};

