                            className={`w-full py-3 border text-[8px] font-black uppercase tracking-[0.2em] border-app-border flex items-center justify-center gap-2 ${!isDisabled ? 'hover:bg-app-accent hover:text-app-accent-text hover:border-app-accent-text' : ''}`}
