// CRITICAL FIX: Bulletproof Sanitizer to prevent Circular JSON errors
const sanitizeDoc = (docSnap: any) => {
    const data = docSnap.data();
    if (!data) return { id: docSnap.id };

    const clean: any = { id: docSnap.id };

    Object.keys(data).forEach(key => {
        const val = data[key];

        if (!val) {
            clean[key] = val;
            return;
        }

        if (typeof val.toMillis === 'function') {
            clean[key] = val.toMillis();
        }
        else if (typeof val === 'object' && typeof val.path === 'string' && typeof val.id === 'string') {
             clean[key] = val.path;
        }
        else if (Array.isArray(val)) {
            clean[key] = val.map((item: any) => {
                if (item && typeof item.toMillis === 'function') return item.toMillis();
                if (item && typeof item.path === 'string' && typeof item.id === 'string') return item.path;
                return item;
            });
        }
        else if (typeof val === 'object') {
             if ('firestore' in val || '_key' in val || 'converter' in val) {
                 clean[key] = null; 
             } else {
                 try {
                     if (Object.prototype.toString.call(val) === '[object Object]') {
                         clean[key] = { ...val };
                     } else {
                         clean[key] = null;
                     }
                 } catch(e) {
                     clean[key] = null;
                 }
             }
        }
        else {
            clean[key] = val;
        }
    });
    return clean;
};

// --- FLIP CARD COMPONENT ---
interface NodeCardProps {
  pkg: Package;
  user: User;
  activePackages: UserPackage[];
  onPurchase: (id: string) => void;
}

const NodeCard: React.FC<NodeCardProps> = ({ 
    pkg, 
    user, 
    activePackages, 
    onPurchase 
}) => {
    const [isFlipped, setIsFlipped] = useState(false);

    const currentActive = activePackages.find(ap => ap.isActive);
    const isCurrent = currentActive?.packageId === pkg.id;
    let isDisabled = false;
    let buttonText = "Deploy";
    let extraInfo = "";
    let isLocked = false;
    let cost = pkg.minAmount;

    if (currentActive) {
        if (isCurrent) { buttonText = "Active"; isDisabled = true; } 
        else if (pkg.minAmount <= currentActive.amount) { buttonText = "N/A"; isDisabled = true; extraInfo = "No downgrades"; } 
        else {
            const upgradeCost = pkg.minAmount - currentActive.amount;
            cost = upgradeCost;
            if (user.capitalBalance < cost) { isLocked = true; isDisabled = true; buttonText = "Locked"; } 
            else { buttonText = "Upgrade"; extraInfo = `Pay: ${upgradeCost.toFixed(0)}`; }
        }
    } else if (user.capitalBalance < cost) { isLocked = true; isDisabled = true; buttonText = "Locked"; }

    // Fallback Image
    const displayImage = pkg.imageUrl || "https://images.unsplash.com/photo-1550751827-4bd374c3f58b?q=80&w=2070&auto=format&fit=crop";

    return (
        <div className="h-[400px] md:h-[550px] perspective-[1000px] group/card">
            <motion.div
                className="w-full h-full relative"
                initial={false}
                animate={{ rotateY: isFlipped ? 180 : 0 }}
                transition={{ duration: 0.6, type: "spring", stiffness: 260, damping: 20 }}
                style={{ transformStyle: "preserve-3d" }}
            >
                {/* FRONT FACE (IMAGE) */}
                <div 
                    className="absolute inset-0 w-full h-full border border-app-border bg-app-bg cursor-pointer group-hover/card:border-app-accent transition-colors overflow-hidden"
                    style={{ backfaceVisibility: "hidden" }}
                    onClick={() => setIsFlipped(true)}
                >
                    <img src={displayImage} alt={pkg.name} className="w-full h-full object-cover opacity-80 group-hover/card:opacity-100 transition-opacity duration-500 scale-100 group-hover/card:scale-105" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-90" />

                    <div className="absolute bottom-0 left-0 right-0 p-4 md:p-8 space-y-2">
                        <div className="flex justify-between items-end">
                            <div className="flex-1 min-w-0 pr-2">
                                <h3 className="text-sm md:text-xl font-black uppercase tracking-tighter text-white truncate">{pkg.name}</h3>
                                <p className="text-[8px] md:text-[10px] font-bold uppercase tracking-widest text-white/60">ROI: {pkg.dailyRoi}% Daily</p>
                            </div>
                            <div className="w-8 h-8 md:w-10 md:h-10 border border-white/20 rounded-full flex items-center justify-center bg-white/5 backdrop-blur-sm shrink-0">
                                <i className="fa-solid fa-arrow-right text-white text-[10px] md:text-xs -rotate-45 group-hover/card:rotate-0 transition-transform"></i>
                            </div>
                        </div>
                    </div>

                    {isCurrent && (
                        <div className="absolute top-4 right-4 px-2 md:px-3 py-1 bg-green-500 text-white text-[8px] md:text-[9px] font-black uppercase tracking-widest">
                            Active
                        </div>
                    )}
                </div>

                {/* BACK FACE (DETAILS) */}
                <div 
                    className={`absolute inset-0 w-full h-full border border-app-border bg-app-bg p-4 md:p-12 flex flex-col justify-between ${isDisabled && !isLocked ? 'opacity-50 grayscale' : ''}`}
                    style={{ backfaceVisibility: "hidden", transform: "rotateY(180deg)" }}
                    onClick={() => setIsFlipped(false)}
                >
                     {/* Close / Flip Back Button */}
                     <button 
                        onClick={(e) => { e.stopPropagation(); setIsFlipped(false); }}
                        className="absolute top-2 right-2 md:top-4 md:right-4 text-app-muted hover:text-app-text transition-colors z-20 p-2"
                     >
                        <i className="fa-solid fa-rotate-left"></i>
                     </button>

                     {isLocked && (
                       <div className="absolute inset-0 z-20 flex flex-col items-center justify-center bg-app-bg/80 backdrop-blur-[2px]">
                          <div className="w-10 h-10 md:w-16 md:h-16 rounded-full bg-app-bg border border-app-border flex items-center justify-center shadow-xl mb-2 md:mb-4"><i className="fa-solid fa-lock text-sm md:text-xl text-app-muted"></i></div>
                          <div className="px-2 md:px-3 py-1 bg-app-bg border border-app-border text-[8px] font-black uppercase tracking-widest text-app-muted">Unlock: ${cost.toFixed(0)}</div>
                       </div>
                     )}

                     <div className={`space-y-3 md:space-y-8 h-full flex flex-col ${isLocked ? 'opacity-30 blur-[1px]' : ''}`}>
                       <div className="flex justify-between items-start pt-2">
                         <h3 className="text-[9px] md:text-xs font-black uppercase tracking-[0.2em] truncate pr-4">{pkg.name}</h3>
                         {isCurrent && <span className="text-[8px] font-black uppercase px-2 py-0.5 bg-green-500 text-white">Online</span>}
                       </div>
                       <div className="space-y-1">
                         <p className="text-2xl md:text-6xl font-black mono tracking-tighter leading-none">${(pkg.minAmount * pkg.dailyRoi / 100).toFixed(2)}</p>
