// RECURSIVE SANITIZER: Handles deep objects and arrays to stripping Firestore internals
const sanitizeValue = (val: any): any => {
    if (!val) return val;
    // Handle Timestamps
    if (typeof val.toMillis === 'function') return val.toMillis();
    // Handle References
    if (typeof val === 'object' && typeof val.path === 'string' && typeof val.id === 'string') return val.path;
    // Handle Arrays
    if (Array.isArray(val)) return val.map(sanitizeValue);
    // Handle Objects
    if (typeof val === 'object') {
        // Strip Firestore internals
        if ('firestore' in val || '_key' in val || 'converter' in val) return null;

        const cleanObj: any = {};
        Object.keys(val).forEach(k => {
            const cleaned = sanitizeValue(val[k]);
            // Only add if not null (unless it was originally null)
            if (cleaned !== null || val[k] === null) {
                cleanObj[k] = cleaned;
            }
        });
        return cleanObj;
    }
    return val;
};

const sanitizeDoc = (docSnap: any) => {
    if (!docSnap.exists()) return null;
    const data = docSnap.data();
    const clean: any = { id: docSnap.id };

    Object.keys(data).forEach(key => {
        clean[key] = sanitizeValue(data[key]);
    });
    return clean;
};

// --- FLIP CARD COMPONENT ---
interface NodeCardProps {
  pkg: Package;
  user: User;
  activePackages: UserPackage[];
  onPurchase: (id: string) => void;
}

const NodeCard: React.FC<NodeCardProps> = ({ 
    pkg, 
    user, 
    activePackages, 
    onPurchase 
}) => {
    const [isFlipped, setIsFlipped] = useState(false);
    const [isSharing, setIsSharing] = useState(false);

    const currentActive = activePackages.find(ap => ap.isActive);
    const isCurrent = currentActive?.packageId === pkg.id;
    let isDisabled = false;
    let buttonText = "Deploy";
    let extraInfo = "";
    let isLocked = false;
    let cost = pkg.minAmount;

    if (currentActive) {
        if (isCurrent) { buttonText = "Active"; isDisabled = true; } 
        else if (pkg.minAmount <= currentActive.amount) { buttonText = "N/A"; isDisabled = true; extraInfo = "No downgrades"; } 
        else {
            const upgradeCost = pkg.minAmount - currentActive.amount;
            cost = upgradeCost;
            if (user.capitalBalance < cost) { isLocked = true; isDisabled = true; buttonText = "Locked"; } 
            else { buttonText = "Upgrade"; extraInfo = `Pay: ${upgradeCost.toFixed(0)}`; }
        }
    } else if (user.capitalBalance < cost) { isLocked = true; isDisabled = true; buttonText = "Locked"; }

    // Fallback Image
    const displayImage = pkg.imageUrl || "https://images.unsplash.com/photo-1550751827-4bd374c3f58b?q=80&w=2070&auto=format&fit=crop";

    const handleShare = async (e: React.MouseEvent) => {
        e.stopPropagation();
        if (isSharing) return;
        setIsSharing(true);

        const cardElement = document.getElementById(`node-card-${pkg.id}`);
        if (cardElement) {
            try {
                // Use html2canvas to screenshot the specific card
                const canvas = await html2canvas(cardElement, { 
                    useCORS: true, 
                    backgroundColor: null, // Transparent bg if possible
                    scale: 2 // Higher quality
                });

                const dataUrl = canvas.toDataURL('image/png');
                const blob = await (await fetch(dataUrl)).blob();
                const file = new File([blob], `${pkg.name.replace(/\s+/g, '_')}_Node.png`, { type: 'image/png' });

                // Try native share first
                if (navigator.share && navigator.canShare && navigator.canShare({ files: [file] })) {
                    try {
                        await navigator.share({
                            title: pkg.name,
                            text: `Check out the ${pkg.name} on QuantumEarn! ROI: ${pkg.dailyRoi}% Daily.`,
                            files: [file]
                        });
                    } catch (shareError: any) {
                         // Fallback to download for errors (like gesture timeout or permission issues)
                         // AbortError usually means user cancelled, so we can ignore or also fallback.
                         // Here we'll fallback for better UX in case of gesture error.
                         if (shareError.name !== 'AbortError') {
                             const link = document.createElement('a');
                             link.download = `${pkg.name}_Node.png`;
                             link.href = dataUrl;
                             link.click();
                         }
                    }
                } else {
                    // Fallback download if share API not supported
                    const link = document.createElement('a');
                    link.download = `${pkg.name}_Node.png`;
                    link.href = dataUrl;
                    link.click();
                }
            } catch (err) {
                console.error("Share generation failed:", err);
                alert("Could not generate image.");
            }
        }
        setIsSharing(false);
    };

    return (
        <div className="aspect-square perspective-[1000px] group/card" id={`node-card-${pkg.id}`}>
            <motion.div
                className="w-full h-full relative"
                initial={false}
                animate={{ rotateY: isFlipped ? 180 : 0 }}
                transition={{ duration: 0.6, type: "spring", stiffness: 260, damping: 20 }}
                style={{ transformStyle: "preserve-3d" }}
            >
                {/* FRONT FACE (IMAGE) */}
                {/* Updated: Border is transparent (invisible) on front face */}
                <div 
                    className="absolute inset-0 w-full h-full border border-transparent bg-app-bg cursor-pointer group-hover/card:border-app-accent transition-colors overflow-hidden"
                    style={{ backfaceVisibility: "hidden" }}
                    onClick={() => setIsFlipped(true)}
                >
                    <img src={displayImage} alt={pkg.name} className="w-full h-full object-cover opacity-80 group-hover/card:opacity-100 transition-opacity duration-500 scale-100 group-hover/card:scale-105" />
                    <div className="absolute inset-0 bg-gradient-to-t from-black via-transparent to-transparent opacity-90" />

                    {/* Tiny Share Icon */}
                    <button 
                        onClick={handleShare}
                        className="absolute top-3 left-3 z-20 w-6 h-6 flex items-center justify-center text-white/50 hover:text-white transition-colors bg-black/20 hover:bg-black/50 rounded-full backdrop-blur-sm"
                        title="Share Node Card"
                    >
                        {isSharing ? (
                            <i className="fa-solid fa-circle-notch fa-spin text-[10px]"></i>
                        ) : (
                            <i className="fa-solid fa-share-nodes text-[10px]"></i>
                        )}
                    </button>

                    <div className="absolute bottom-0 left-0 right-0 p-3 md:p-8 space-y-1 md:space-y-2">
                        <div className="flex justify-between items-end">
